    #[test]
    fn item_create_rewrite_reports_typed_source_bit_claim_for_ledger() {
        let mut live = diagnostic_model_type2_typed_item_create_record();
        let mut record_end = live.len();
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        let source_record_bits = [false, false, true, false, false];
        let following_record_bits = [true, false];
        fragment_bits.extend_from_slice(&source_record_bits);
        fragment_bits.extend_from_slice(&following_record_bits);
        let add_start_bit_cursor = CNW_FRAGMENT_HEADER_BITS;

        let rewrite = appearance::insert_ee_item_create_extras_for_ee(
            &mut live,
            2,
            &mut record_end,
            &mut fragment_bits,
            add_start_bit_cursor,
        )
        .expect("typed A/6 item-create rewrite should expose its bit claim");

        assert_eq!(rewrite.bits_inserted, 1);
        assert_eq!(
            rewrite.source_fragment_bits_consumed,
            Some(source_record_bits.len())
        );
        assert_eq!(
            rewrite.emitted_fragment_bits_consumed,
            Some(source_record_bits.len() + rewrite.bits_inserted)
        );

        let mut emitted_cursor = add_start_bit_cursor;
        assert!(add::advance_verified_add_record(
            &live,
            0,
            record_end,
            &fragment_bits,
            &mut emitted_cursor,
        ));
        assert_eq!(
            emitted_cursor,
            add_start_bit_cursor + rewrite.emitted_fragment_bits_consumed.unwrap()
        );
        assert_eq!(
            &fragment_bits[emitted_cursor..],
            &following_record_bits,
            "the inserted EE active-property bit must stay inside A/6"
        );

        let mut ledger = LiveObjectRewriteBitLedger::new();
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end,
                emitted_bit_start: add_start_bit_cursor,
                emitted_bit_end: emitted_cursor,
                bits_inserted: rewrite.bits_inserted,
                bits_removed: rewrite.bits_removed,
                family: "item-create-rewrite",
            },
        ));

        let entry = ledger
            .entries()
            .last()
            .expect("ledger should contain the item-create row");
        assert_eq!(entry.family, "item-create-rewrite");
        assert_eq!(entry.source_bit_start, add_start_bit_cursor);
        assert_eq!(
            entry.source_bit_end,
            add_start_bit_cursor + source_record_bits.len()
        );
        assert_eq!(entry.emitted_bit_end, emitted_cursor);
        let shifted_candidate = ledger
            .gap_before_cursor(emitted_cursor + 2)
            .expect("shifted U/6 neighbor should be classified after A/6");
        assert_eq!(shifted_candidate.previous_family, "item-create-rewrite");
        assert_eq!(shifted_candidate.source_relation, "unowned-source-gap");
        assert_eq!(shifted_candidate.source_gap_bits, 2);
    }

    #[test]
    fn item_unowned_neighbor_retains_focus_cursor_failure() {
        let mut live = diagnostic_model_type2_typed_item_create_record();
        let item_offset = live.len();
        live.extend_from_slice(&diagnostic_full_item_update_live_bytes());

        let add_start_bit_cursor = CNW_FRAGMENT_HEADER_BITS;
        let add_source_bits = [false, false, true, false, false];
        let add_emitted_bits = [false, false, false, true, false, false];
        let mut shifted_item_bits = vec![false, true];
        shifted_item_bits.extend_from_slice(&[
            true, true, // position residuals if an external owner consumed the gap.
            false, true, false, true, true, // scalar orientation branch plus residuals.
            false, false, false, false, false, // item state bits.
            false, // direct CExoString item name.
        ]);

        let mut source_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        source_bits.extend_from_slice(&add_source_bits);
        source_bits.extend_from_slice(&shifted_item_bits);
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend_from_slice(&add_emitted_bits);
        fragment_bits.extend_from_slice(&shifted_item_bits);

        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        let item_bit_cursor = add_start_bit_cursor + add_emitted_bits.len();
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: item_offset,
                emitted_bit_start: add_start_bit_cursor,
                emitted_bit_end: item_bit_cursor,
                bits_inserted: 1,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        let neighbor = nearest_unowned_item_update_neighbor_cursor(
            &live,
            item_offset,
            live.len(),
            &fragment_bits,
            item_bit_cursor,
            &ledger,
        )
        .expect("the scalar-shaped item row should validate only after a two-bit gap");

        assert_eq!(neighbor.delta, 2);
        assert_eq!(neighbor.emitted_gap_bits, 2);
        assert_eq!(neighbor.source_gap_bits, 2);
        assert_eq!(neighbor.previous_family, "item-create-rewrite");
        assert_eq!(
            neighbor.gap_origin,
            LiveObjectUpdateItemCursorGapOrigin::FocusPositionBits,
            "the +2 scalar neighbor starts only after the inherited cursor's item position bits"
        );
        assert_ne!(
            neighbor.focus_failure_stage, "none",
            "the valid neighbor must retain the inherited-cursor parse failure"
        );
        assert_eq!(
            neighbor.focus_failure_orientation_vector,
            Some(true),
            "the real cursor selects the vector branch before the scalar-shaped neighbor fits"
        );
        assert!(neighbor.focus_failure_bit_cursor >= item_bit_cursor);
    }

    #[test]
    fn item_failure_source_window_neighbor_fit_reports_focus_row_start() {
        let mut live = Vec::new();
        live.extend_from_slice(&[b'D', ITEM_OBJECT_TYPE, 0x20, 0, 0, 0]);
        let item_offset = live.len();
        live.extend_from_slice(&diagnostic_full_item_update_live_bytes());

        let rows = live_object_source_window_rows(&live, item_offset, live.len(), 1, 0);
        let mut fragment_bits = vec![false, false, false, false];
        fragment_bits.extend_from_slice(&[
            false, true, // unowned residue before the item update.
            true, true, // item position residuals if a prior owner consumed the residue.
            false, true, false, true, true, // scalar-orientation selector plus residual bits.
            false, false, false, false, false, // item state bits.
            false, // direct CExoString item name.
        ]);
        let claims = live_object_source_window_row_bit_claims(
            &live,
            &rows,
            &fragment_bits,
            CNW_FRAGMENT_HEADER_BITS,
        );

        assert_eq!(claims.len(), 2);
        assert_eq!(claims[0].family, "delete");
        assert_eq!(claims[0].bit_end, Some(CNW_FRAGMENT_HEADER_BITS + 1));
        assert_eq!(claims[1].offset, item_offset);
        assert_eq!(claims[1].bit_start, CNW_FRAGMENT_HEADER_BITS + 1);
        assert_eq!(claims[1].bit_end, None);

        let neighbors = live_object_source_window_item_neighbor_cursor_claims(
            &live,
            &rows[1],
            &fragment_bits,
            claims[1].bit_start,
            claims[0].bit_end,
            &LiveObjectRewriteBitLedger::new(),
        );
        let plus_two = neighbors
            .iter()
            .find(|neighbor| neighbor.delta == 2)
            .expect("the active scalar-shaped item bytes should validate only at cursor +2");
        assert_eq!(plus_two.bit_start, claims[1].bit_start + 2);
        assert_eq!(plus_two.relation, "inside-focus-row");
        assert_eq!(
            plus_two.translated_mask,
            super::item::translate_update_mask(0xFFFF_FFF3)
        );
        assert_eq!(plus_two.orientation_vector, Some(false));
        assert_eq!(
            plus_two.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::NoLedger
        );
        assert_eq!(
            plus_two.bit_end.saturating_sub(plus_two.bit_start),
            LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS
                + LEGACY_UPDATE_STATE_FRAGMENT_BITS
                + 1,
            "the nearby fit is a scalar item claim, not a prior-row owner"
        );
        assert_eq!(
            plus_two.read_end,
            live.len(),
            "the nearby item candidate consumes the bounded U/6 read bytes"
        );
    }

    #[test]
    fn item_neighbor_gap_origin_advances_through_orientation_branch_before_state() {
        let mask = LEGACY_UPDATE_POSITION_MASK
            | LEGACY_UPDATE_ORIENTATION_MASK
            | LEGACY_UPDATE_STATE_MASK
            | LEGACY_UPDATE_NAME_MASK;
        let focus = 20usize;
        let scalar_orientation_end = focus
            + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
            + 1
            + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS;
        let vector_orientation_end = focus
            + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
            + 1
            + EE_UPDATE_ORIENTATION_VECTOR_FRAGMENT_BITS;

        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(false),
                focus,
                scalar_orientation_end
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusOrientationScalarPrefixBits,
            "a scalar branch fit at the orientation end is still orientation-owned"
        );
        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(false),
                focus,
                scalar_orientation_end + 1
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusStatePrefixBits,
            "state attribution must start after the scalar orientation payload"
        );
        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(false),
                focus,
                scalar_orientation_end + LEGACY_UPDATE_STATE_FRAGMENT_BITS + 1
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusNameOrLocstringPrefixBits,
            "name attribution must start only after scalar orientation and state bits"
        );

        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(true),
                focus,
                vector_orientation_end
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusOrientationVectorPrefixBits,
            "a vector branch fit at the orientation end is still orientation-owned"
        );
        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(true),
                focus,
                vector_orientation_end + 1
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusStatePrefixBits,
            "state attribution must start after the vector orientation payload"
        );
    }

    #[test]
    fn rewrite_bit_ledger_tracks_source_and_emitted_cursors() {
        let mut live = vec![0; 32];
        live[0] = b'A';
        live[1] = DOOR_OBJECT_TYPE;
        live[6] = b'U';
        live[7] = DOOR_OBJECT_TYPE;
        live[16] = b'A';
        live[17] = ITEM_OBJECT_TYPE;
        let mut ledger = LiveObjectRewriteBitLedger::new();

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: 6,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 6,
                bits_inserted: 0,
                bits_removed: 0,
                family: "add-exact",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 6,
                record_end: 16,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 6,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 19,
                bits_inserted: 6,
                bits_removed: 1,
                family: "update-rewrite",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 16,
                record_end: 32,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 19,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 25,
                bits_inserted: 1,
                bits_removed: 0,
                family: "add-rewrite",
            },
        ));

        let entries = ledger.entries();
        assert_eq!(entries.len(), 3);
        assert_eq!(entries[0].source_bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(entries[0].source_bit_end, CNW_FRAGMENT_HEADER_BITS + 6);
        assert_eq!(entries[1].source_bit_start, CNW_FRAGMENT_HEADER_BITS + 6);
        assert_eq!(
            entries[1].source_bit_end,
            CNW_FRAGMENT_HEADER_BITS + 14,
            "six inserted EE bits and one removed legacy bit mean the source row consumed eight bits"
        );
        assert_eq!(entries[1].emitted_bit_end, CNW_FRAGMENT_HEADER_BITS + 19);
        assert_eq!(entries[2].source_bit_start, CNW_FRAGMENT_HEADER_BITS + 14);
        assert_eq!(entries[2].source_bit_end, CNW_FRAGMENT_HEADER_BITS + 19);
        assert_eq!(entries[2].emitted_bit_end, CNW_FRAGMENT_HEADER_BITS + 25);
        assert_eq!(
            ledger.source_bit_cursor(),
            CNW_FRAGMENT_HEADER_BITS + 19,
            "the source cursor remains distinct from the EE-emitted cursor after insertions"
        );
    }

    #[test]
    fn rewrite_bit_ledger_rejects_source_span_past_snapshot() {
        let mut live = vec![0; 8];
        live[0] = b'A';
        live[1] = ITEM_OBJECT_TYPE;
        let source_bits = vec![false; CNW_FRAGMENT_HEADER_BITS + 2];
        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);

        assert!(!ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 3,
                bits_inserted: 0,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));
        assert_eq!(
            ledger.source_bit_cursor(),
            CNW_FRAGMENT_HEADER_BITS,
            "an impossible source claim must not advance the ledger cursor"
        );
        assert!(ledger.entries().is_empty());

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 2,
                bits_inserted: 0,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));
        assert_eq!(ledger.source_bit_cursor(), source_bits.len());
    }

