    #[test]
    fn rewrite_bit_ledger_rejects_impossible_source_delta_claims() {
        let mut live = vec![0; 8];
        live[0] = b'U';
        live[1] = ITEM_OBJECT_TYPE;
        let mut ledger = LiveObjectRewriteBitLedger::new();

        assert!(!ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 4,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS,
                bits_inserted: 0,
                bits_removed: 0,
                family: "update-rewrite",
            },
        ));
        assert_eq!(ledger.source_bit_cursor(), CNW_FRAGMENT_HEADER_BITS);
        assert!(ledger.entries().is_empty());

        assert!(!ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 1,
                bits_inserted: 2,
                bits_removed: 0,
                family: "update-rewrite",
            },
        ));
        assert_eq!(
            ledger.source_bit_cursor(),
            CNW_FRAGMENT_HEADER_BITS,
            "an impossible EE insertion claim must not advance the source cursor"
        );
        assert!(ledger.entries().is_empty());
    }

    #[test]
    fn item_update_cursor_failure_kind_uses_ledger_gap_shape() {
        let mut live = vec![0; 16];
        live[0] = b'A';
        live[1] = ITEM_OBJECT_TYPE;

        let mut ledger = LiveObjectRewriteBitLedger::new();
        assert_eq!(
            ledger.item_update_cursor_failure_kind(CNW_FRAGMENT_HEADER_BITS),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorWithoutLedger
        );

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 4,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 8,
                bits_inserted: 0,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        assert_eq!(
            ledger.item_update_cursor_failure_kind(CNW_FRAGMENT_HEADER_BITS + 2),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorBeforeLedgerRow
        );
        assert_eq!(
            ledger.item_update_cursor_failure_kind(CNW_FRAGMENT_HEADER_BITS + 6),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorInsideLedgerRow
        );
        let cursor_after_row = CNW_FRAGMENT_HEADER_BITS + 8;
        assert_eq!(
            ledger.item_update_cursor_failure_kind(cursor_after_row),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorAfterLedgerHandoff
        );
        let exact_verdict =
            live_object_item_update_cursor_handoff_verdict(&ledger, cursor_after_row);
        assert_eq!(
            exact_verdict.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::ContiguousTail
        );
        assert!(exact_verdict.claimable_handoff);
        assert_eq!(exact_verdict.handoff_blocker, "none");
        let inside_verdict =
            live_object_item_update_cursor_handoff_verdict(&ledger, CNW_FRAGMENT_HEADER_BITS + 6);
        assert_eq!(
            inside_verdict.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::InsidePreviousRow
        );
        assert!(!inside_verdict.claimable_handoff);
        assert_eq!(inside_verdict.handoff_blocker, "inside-previous-row");
        assert_eq!(
            ledger.item_update_cursor_failure_kind(CNW_FRAGMENT_HEADER_BITS + 10),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorAfterUnownedLedgerGap
        );
        let unowned_verdict =
            live_object_item_update_cursor_handoff_verdict(&ledger, CNW_FRAGMENT_HEADER_BITS + 10);
        assert_eq!(
            unowned_verdict.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::UnownedEmittedAndSourceGap
        );
        assert!(!unowned_verdict.claimable_handoff);
        assert_eq!(
            unowned_verdict.handoff_blocker,
            "unowned-emitted-source-gap"
        );
        let unowned_neighbor = LiveObjectItemUpdateUnownedNeighbor {
            delta: 2,
            bit_start: CNW_FRAGMENT_HEADER_BITS + 10,
            bit_end: CNW_FRAGMENT_HEADER_BITS + 20,
            read_end: live.len(),
            translated_mask: 0x0008_0033,
            orientation_vector: Some(false),
            emitted_gap_bits: 2,
            emitted_gap_bit_start: cursor_after_row,
            emitted_gap_bit_end: cursor_after_row + 2,
            emitted_gap_values: live_object_rewrite_bit_slice_evidence(
                cursor_after_row,
                cursor_after_row + 2,
                &[true, false],
            ),
            source_gap_bits: 2,
            source_gap_bit_start: cursor_after_row,
            source_gap_bit_end: cursor_after_row + 2,
            source_gap_values: live_object_rewrite_bit_slice_evidence(
                cursor_after_row,
                cursor_after_row + 2,
                &[false, true],
            ),
            previous_offset: 0,
            previous_record_end: live.len(),
            previous_family: "item-create-rewrite",
            gap_origin: LiveObjectUpdateItemCursorGapOrigin::FocusPositionBits,
            source_owner: LiveObjectUpdateItemCursorSourceOwner::UnownedEmittedAndSourceGap,
            claimable_handoff: false,
            handoff_blocker: "unowned-emitted-source-gap",
            focus_failure_stage: "orientation-vector-read-bytes",
            focus_failure_mask: Some(0x0008_0033),
            focus_failure_read_cursor: 12,
            focus_failure_bit_cursor: cursor_after_row + 2,
            focus_failure_orientation_vector: Some(true),
        };
        assert_eq!(
            ledger.item_update_cursor_failure_kind_with_unowned_neighbor(
                cursor_after_row,
                Some(unowned_neighbor),
            ),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorBeforeValidNeighborUnownedGap
        );
        assert_eq!(
            ledger.item_update_cursor_failure_kind_with_unowned_neighbor(
                CNW_FRAGMENT_HEADER_BITS + 6,
                Some(unowned_neighbor),
            ),
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorInsideLedgerRow,
            "a validating neighbor must not hide that the inherited cursor overlaps the prior row"
        );
    }

    #[test]
    fn item_update_cursor_failure_evidence_keeps_contiguous_tail_chain() {
        let mut live = vec![0; 32];
        live[0] = b'A';
        live[1] = DOOR_OBJECT_TYPE;
        live[6] = b'U';
        live[7] = DOOR_OBJECT_TYPE;
        live[16] = b'A';
        live[17] = ITEM_OBJECT_TYPE;
        let source_bits = (0..32).map(|index| index % 2 == 0).collect::<Vec<_>>();
        let emitted_bits = (0..32).map(|index| index % 2 != 0).collect::<Vec<_>>();

        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: 6,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 5,
                bits_inserted: 0,
                bits_removed: 0,
                family: "door-add-rewrite",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 6,
                record_end: 16,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 5,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 13,
                bits_inserted: 0,
                bits_removed: 0,
                family: "door-update-tail9-rewrite",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 16,
                record_end: 22,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 13,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 19,
                bits_inserted: 1,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        let bit_cursor = CNW_FRAGMENT_HEADER_BITS + 19;
        let failure = LiveObjectItemUpdateCursorFailure {
            kind: ledger.item_update_cursor_failure_kind(bit_cursor),
            offset: 22,
            record_end: 32,
            bit_cursor,
            focus_failure: None,
            focus_cursor_ledger: live_object_item_cursor_ledger_evidence(
                &ledger,
                &emitted_bits,
                bit_cursor,
            ),
            focus_failure_read_window: None,
            focus_failure_bit_window: None,
            unowned_neighbor: None,
            contiguous_tail: ledger.contiguous_tail_evidence(&emitted_bits, bit_cursor),
            source_window: None,
        }
        .into_rewrite_failure();

        assert_eq!(
            failure.kind,
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorAfterLedgerHandoff
        );
        let evidence = failure
            .item_update_cursor_evidence
            .expect("item cursor failure should carry evidence");
        let focus_cursor = evidence
            .focus_cursor_ledger
            .expect("failure evidence should preserve the focus cursor ledger verdict");
        assert_eq!(
            focus_cursor.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::ContiguousTail,
            "the inherited cursor is source-owned even when the item parser rejects"
        );
        assert_eq!(focus_cursor.ledger_relation, "after-previous-emitted-end");
        assert_eq!(
            focus_cursor.ledger_source_relation,
            "after-previous-source-end"
        );
        assert_eq!(focus_cursor.ledger_emitted_gap_bits, Some(0));
        assert_eq!(focus_cursor.ledger_source_gap_bits, Some(0));
        assert_eq!(
            focus_cursor.ledger_previous_family,
            Some("item-create-rewrite")
        );
        let tail = evidence
            .contiguous_tail
            .expect("failure evidence should preserve the contiguous ledger tail");
        assert_eq!(tail.entry_count, 3);
        assert_eq!(tail.entries_retained, 3);
        assert_eq!(tail.source_bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(tail.source_bit_end, CNW_FRAGMENT_HEADER_BITS + 18);
        assert_eq!(tail.emitted_bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(tail.emitted_bit_end, bit_cursor);
        assert_eq!(tail.emitted_cursor, bit_cursor);
        assert_eq!(tail.source_cursor, CNW_FRAGMENT_HEADER_BITS + 18);
        assert_eq!(tail.emitted_source_delta, 1);
        assert_eq!(tail.emitted_gap_to_cursor, 0);
        assert_eq!(tail.source_gap_to_cursor, 0);

        let families = tail
            .entries
            .iter()
            .flatten()
            .map(|entry| entry.family)
            .collect::<Vec<_>>();
        assert_eq!(
            families,
            vec![
                "door-add-rewrite",
                "door-update-tail9-rewrite",
                "item-create-rewrite"
            ]
        );
        assert_eq!(
            tail.entries[2].map(|entry| (entry.offset, entry.record_end, entry.bits_inserted)),
            Some((16, 22, 1))
        );
        let item_entry = tail.entries[2].expect("third retained entry should be the A/6 row");
        assert_eq!(item_entry.source_bits.bit_count, 5);
        assert_eq!(item_entry.source_bits.bits_retained, 5);
        assert_eq!(
            item_entry.source_bits.bits[0],
            Some(source_bits[CNW_FRAGMENT_HEADER_BITS + 13])
        );
        assert_eq!(item_entry.emitted_bits.bit_count, 6);
        assert_eq!(item_entry.emitted_bits.bits_retained, 6);
        assert_eq!(
            item_entry.emitted_bits.bits[0],
            Some(emitted_bits[CNW_FRAGMENT_HEADER_BITS + 13])
        );
    }

    #[test]
    fn exact_placeable_add_and_update_mentions_expose_state_bits() {
        let object_id = 0x8000_34D8u32;
        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_STATE_MASK.to_le_bytes());

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            true,  // static/plot state.
            true,  // useable.
            false, // trap disarmable.
            true,  // lockable.
            false, // locked.
            false, // unknown 0x1AC sibling.
            true,  // name-valid.
            false, // EE-only light/visual guard before the transform map.
            false, // update visual selector.
            false, // update visual state active.
            true,  // update locked.
            true,  // update lockable.
            false, // update visual payload.
            false, // EE-only door/placeable state guard.
        ]);
        let payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("live-object payload");

        let claim = claim_payload_if_verified(&payload).expect("exact live-object claim");
        assert_eq!(claim.mentions.len(), 2);
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0011,
                resref: None,
            })
        );
        assert_eq!(claim.mentions[1].placeable_appearance, None);
        assert_eq!(
            claim.mentions[0].placeable_state,
            Some(LiveObjectPlaceableState {
                useable: Some(true),
                trap_disarmable: Some(false),
                lockable: Some(true),
                locked: Some(false),
            })
        );
        assert_eq!(
            claim.mentions[1].placeable_state,
            Some(LiveObjectPlaceableState {
                lockable: Some(true),
                locked: Some(true),
                ..LiveObjectPlaceableState::default()
            })
        );
    }

    #[test]
    fn exact_placeable_update_mentions_expose_verified_appearance_cursor() {
        let object_id = 0x8000_34D8u32;
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0x0022u16.to_le_bytes());
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        let payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("appearance U/09");

        let claim = claim_payload_if_verified(&payload).expect("exact appearance U/09");
        assert_eq!(claim.mentions.len(), 1);
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0022,
                resref: None,
            })
        );

        let resref = *b"plc_visual_test\0";
        live.truncate(10);
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&resref);
        fragment_bits.truncate(CNW_FRAGMENT_HEADER_BITS);
        let payload = live_object_payload_from_parts(&live, &fragment_bits).expect("resref U/09");

        let claim = claim_payload_if_verified(&payload).expect("exact resref U/09");
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(resref),
            }),
            "the update mention must use the parser-owned appearance offset before the resref branch"
        );
    }

    #[test]
    fn exact_placeable_update_mentions_share_verified_scalar_claim() {
        let object_id = 0x8000_34D8u32;
        let mask = LEGACY_UPDATE_POSITION_MASK
            | LEGACY_UPDATE_ORIENTATION_MASK
            | LEGACY_UPDATE_APPEARANCE_MASK
            | LEGACY_UPDATE_STATE_MASK;
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&mask.to_le_bytes());
        live.extend_from_slice(&[0x10, 0x00, 0x20, 0x00, 0x30, 0x00]);
        live.push(0x70);
        live.extend_from_slice(&0x0022u16.to_le_bytes());

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, true, // position fragment bits.
            false, true, false, true, false, // scalar orientation 0x70A.
            false, true, false, true, false, // lockable=true, locked=false.
            false, // EE-only door/placeable state guard.
        ]);
        let payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("exact scalar U/09");

        let claim = claim_payload_if_verified(&payload).expect("exact scalar U/09 should claim");
        assert_eq!(claim.mentions.len(), 1);
        assert!(
            claim.mentions[0].position.is_some(),
            "position bits must be owned before the scalar orientation cursor"
        );
        assert_eq!(
            claim.mentions[0].orientation,
            Some(LiveObjectRecordOrientation {
                source: LiveObjectRecordOrientationSource::Scalar,
                scalar_tenths_degrees: 0x70A,
                vector: None,
            })
        );
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0022,
                resref: None,
            })
        );
        assert_eq!(
            claim.mentions[0].placeable_state,
            Some(LiveObjectPlaceableState {
                lockable: Some(true),
                locked: Some(false),
                ..LiveObjectPlaceableState::default()
            }),
            "orientation, appearance, and state must share the verified U/09 parser cursor"
        );
        assert_eq!(
            claim.mentions[0].fragment_bit_end,
            CNW_FRAGMENT_HEADER_BITS
                + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS
                + LEGACY_UPDATE_STATE_FRAGMENT_BITS
                + 1
        );
    }

    #[test]
