    #[test]
    fn exact_placeable_add_module_custom_pre_add_only_synthesizes_following_update() {
        let object_id = 0x8000_34D8u32;
        let target_resref = *b"plc_custom_add\0\0";
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        let add_offset = live.len();
        live.extend_from_slice(&[b'A', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            true,  // useable already matches the module-backed row.
            false, // trap disarmable already matches.
            true,  // lockable already matches.
            false, // locked already matches.
            false, // unknown 0x1AC sibling stays packet-authored.
            true,  // name-valid stays packet-authored.
            false, // EE-only light/visual guard before the transform map.
        ]);
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("U/09 + A/09 payload");
        let pre_claim =
            claim_payload_if_verified(&payload).expect("pre-rewrite exact U/09 + A/09 claim");
        assert_eq!(pre_claim.mentions.len(), 2);
        assert_eq!(
            pre_claim.mentions[0].placeable_appearance_claim,
            Some(LiveObjectPlaceableAppearanceClaim {
                appearance_offset: LEGACY_UPDATE_HEADER_BYTES,
                resref_offset: None,
            }),
            "the earlier U/09 owns a normal appearance WORD before the add"
        );
        assert_eq!(
            pre_claim.mentions[1].placeable_appearance_claim,
            Some(LiveObjectPlaceableAppearanceClaim {
                appearance_offset: add_offset + 11,
                resref_offset: None,
            }),
            "A/09 still owns only its fixed-width appearance WORD"
        );

        let area_context = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0xFFFE,
                module_template_resref: Some(target_resref),
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    useable: true,
                    trap_flag: false,
                    trap_disarmable: false,
                    lockable: true,
                    locked: false,
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("the prior U/09 should rewrite and the later A/09 should synthesize a carrier");
        let expected_bytes_inserted = EE_UPDATE_APPEARANCE_RESREF_READ_BYTES
            + LEGACY_UPDATE_HEADER_BYTES
            + EE_UPDATE_APPEARANCE_WORD_READ_BYTES
            + EE_UPDATE_APPEARANCE_RESREF_READ_BYTES;
        assert_eq!(summary.add_records_examined, 1);
        assert_eq!(summary.update_records_examined, 1);
        assert_eq!(summary.add_records_rewritten, 1);
        assert_eq!(summary.update_records_rewritten, 1);
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_with_update,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_normal_update,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_update_only,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_normal_update_only,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_normal_update_only_custom_rewrite_ready,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_normal_update_only_custom_rewrite_blocked,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_custom_update_only,
            0
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_add_only,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update,
            1
        );
        assert_synthesized_custom_carrier_origins(&summary, 1, 0);
        assert_synthesized_custom_carrier_after_add_reasons(&summary, 0, 1, 0, 0);
        assert_eq!(summary.exact_placeable_update_appearance_rewritten, 1);
        assert_eq!(summary.bytes_inserted, expected_bytes_inserted as u32);
        assert_eq!(
            summary.new_live_bytes_length,
            summary.old_live_bytes_length + expected_bytes_inserted
        );

        let claim = claim_payload_if_verified(&payload)
            .expect("post-rewrite exact custom U/09 + fixed-width A/09 + synthesized U/09 claim");
        assert_eq!(claim.mentions.len(), 3);
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            }),
            "the prior update can be widened for its own parser-owned branch"
        );
        assert_eq!(
            claim.mentions[1].record_offset,
            add_offset + EE_UPDATE_APPEARANCE_RESREF_READ_BYTES
        );
        assert_eq!(
            claim.mentions[1].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0011,
                resref: None,
            }),
            "the following add remains fixed-width and packet-authored"
        );
        let synthesized_offset = live.len() + EE_UPDATE_APPEARANCE_RESREF_READ_BYTES;
        assert_eq!(claim.mentions[2].record_offset, synthesized_offset);
        assert_eq!(
            claim.mentions[2].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            }),
            "a following synthetic U/09 now carries the add's custom TemplateResRef"
        );
        assert_eq!(
            claim.mentions[2].placeable_appearance_claim,
            Some(LiveObjectPlaceableAppearanceClaim {
                appearance_offset: synthesized_offset + LEGACY_UPDATE_HEADER_BYTES,
                resref_offset: Some(
                    synthesized_offset
                        + LEGACY_UPDATE_HEADER_BYTES
                        + EE_UPDATE_APPEARANCE_WORD_READ_BYTES
                ),
            })
        );
        assert_eq!(
            claim.mentions[2].fragment_bit_start, claim.mentions[1].fragment_bit_end,
            "the synthesized carrier starts from the add-owned next cursor"
        );
        assert_eq!(
            claim.mentions[2].fragment_bit_end, claim.mentions[1].fragment_bit_end,
            "the synthesized carrier consumes no fragment bits"
        );
    }

    #[test]
    fn exact_placeable_add_module_custom_carrier_retains_nearest_update_details() {
        let object_id = 0x8000_34D8u32;
        let pre_add_resref = *b"plc_pre_update\0\0";
        let following_resref = *b"plc_follow_updt\0";

        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        let pre_add_normal_offset = 0usize;

        let pre_add_custom_offset = live.len();
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&pre_add_resref);

        let add_offset = live.len();
        live.extend_from_slice(&[b'A', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();

        let following_normal_offset = live.len();
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0x0022u16.to_le_bytes());

        let following_custom_offset = live.len();
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&following_resref);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            true,  // useable.
            false, // trap disarmable.
            true,  // lockable.
            false, // locked.
            false, // unknown 0x1AC sibling.
            true,  // name-valid.
            false, // EE-only light/visual guard before the transform map.
        ]);
        let payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("mixed U/A payload");
        let claim = claim_payload_if_verified(&payload).expect("mixed U/A claim");
        let carrier = exact_placeable_update_appearance_carrier_for_add(
            &crate::translate::area::AreaPlaceableContext::default(),
            &claim,
            object_id,
            add_offset,
            add_end,
        );

        assert_eq!(carrier.following_kind(), "normal+custom");
        assert_eq!(carrier.pre_add_kind(), "normal+custom");
        assert_eq!(
            carrier.following_normal.map(|record| record.record_offset),
            Some(following_normal_offset)
        );
        assert_eq!(
            carrier.following_custom.map(|record| {
                (
                    record.record_offset,
                    record.appearance_offset,
                    record.resref_offset,
                    record.source_appearance,
                    record.source_resref,
                )
            }),
            Some((
                following_custom_offset,
                following_custom_offset + LEGACY_UPDATE_HEADER_BYTES,
                Some(
                    following_custom_offset
                        + LEGACY_UPDATE_HEADER_BYTES
                        + EE_UPDATE_APPEARANCE_WORD_READ_BYTES,
                ),
                0xFFFE,
                Some(following_resref),
            ))
        );
        assert_eq!(
            carrier.pre_add_normal.map(|record| record.record_offset),
            Some(pre_add_normal_offset)
        );
        assert_eq!(
            carrier.pre_add_custom.map(|record| {
                (
                    record.record_offset,
                    record.appearance_offset,
                    record.resref_offset,
                    record.source_appearance,
                    record.source_resref,
                )
            }),
            Some((
                pre_add_custom_offset,
                pre_add_custom_offset + LEGACY_UPDATE_HEADER_BYTES,
                Some(
                    pre_add_custom_offset
                        + LEGACY_UPDATE_HEADER_BYTES
                        + EE_UPDATE_APPEARANCE_WORD_READ_BYTES,
                ),
                0xFFFE,
                Some(pre_add_resref),
            ))
        );
        assert_eq!(
            carrier
                .selected_following()
                .map(|record| record.record_offset),
            Some(following_custom_offset),
            "custom following rows are the actionable parser-owned carrier"
        );
        assert_eq!(
            carrier
                .selected_pre_add()
                .map(|record| record.record_offset),
            Some(pre_add_custom_offset),
            "pre-add rows are logged as evidence but do not carry the add"
        );

        let add_mention = claim
            .mentions
            .iter()
            .find(|mention| mention.record_offset == add_offset)
            .expect("claim should retain the fixed-width A/09 mention");
        assert_eq!(
            add_mention.placeable_appearance_claim,
            Some(LiveObjectPlaceableAppearanceClaim {
                appearance_offset: add_offset + 11,
                resref_offset: None,
            }),
            "A/09 remains a fixed-width WORD-only add-tail owner"
        );
    }

    #[test]
    fn exact_placeable_add_module_custom_carrier_stops_at_lifecycle_fences() {
        let object_id = 0x8000_34D9u32;
        let pre_add_resref = *b"plc_pre_fenced\0\0";
        let following_resref = *b"plc_post_fence\0\0";

        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&pre_add_resref);

        live.extend_from_slice(&[b'D', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());

        let add_offset = live.len();
        live.extend_from_slice(&[b'A', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();

        live.extend_from_slice(&[b'D', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());

        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&following_resref);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.push(false); // pre-add D/09 owns one delete BOOL.
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            true,  // useable.
            false, // trap disarmable.
            true,  // lockable.
            false, // locked.
            false, // unknown 0x1AC sibling.
            true,  // name-valid.
            false, // EE-only light/visual guard before the transform map.
        ]);
        fragment_bits.push(false); // following D/09 owns one delete BOOL.
        let payload = live_object_payload_from_parts(&live, &fragment_bits)
            .expect("U/09, D/09, A/09, D/09, U/09 payload");
        let claim = claim_payload_if_verified(&payload).expect("lifecycle-fenced carrier claim");

        let carrier = exact_placeable_update_appearance_carrier_for_add(
            &crate::translate::area::AreaPlaceableContext::default(),
            &claim,
            object_id,
            add_offset,
            add_end,
        );

        assert_eq!(
            carrier.following_kind(),
            "none",
            "a following U/09 after a same-object A/D fence belongs to a later lifecycle"
        );
        assert_eq!(
            carrier.pre_add_kind(),
            "none",
            "a pre-add U/09 before a same-object A/D fence belongs to an earlier lifecycle"
        );
        assert_eq!(
            carrier.synthesis_policy(),
            ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddWithoutCarrier
        );
    }

    #[test]
    fn exact_placeable_add_lifecycle_fenced_custom_update_does_not_suppress_synthesis() {
        let object_id = 0x8000_34DAu32;
        let target_resref = *b"plc_target_fen\0\0";
        let later_resref = *b"plc_later_fen\0\0\0";

        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();

        live.extend_from_slice(&[b'D', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());

        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&later_resref);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            true,  // useable already matches the module-backed row.
            false, // trap disarmable already matches.
            true,  // lockable already matches.
            false, // locked already matches.
            false, // unknown 0x1AC sibling stays packet-authored.
            true,  // name-valid stays packet-authored.
            false, // EE-only light/visual guard before the transform map.
        ]);
        fragment_bits.push(false); // D/09 placeable delete owns one BOOL.
        let mut payload = live_object_payload_from_parts(&live, &fragment_bits)
            .expect("A/09, D/09, lifecycle-fenced custom U/09 payload");

        let area_context = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0xFFFE,
                module_template_resref: Some(target_resref),
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    useable: true,
                    trap_flag: false,
                    trap_disarmable: false,
                    lockable: true,
                    locked: false,
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("lifecycle-fenced custom U/09 must not suppress A/09 carrier synthesis");
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_with_update, 0,
            "the post-delete U/09 is not a carrier for the earlier add"
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_add_only,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update,
            1
        );
        assert_synthesized_custom_carrier_origins(&summary, 1, 0);
        assert_synthesized_custom_carrier_after_add_reasons(&summary, 1, 0, 0, 0);

        let claim = claim_payload_if_verified(&payload)
            .expect("post-rewrite lifecycle-fenced custom carrier payload should exact-claim");
        assert_eq!(claim.mentions.len(), 4);
        assert_eq!(claim.mentions[1].record_offset, add_end);
        assert_eq!(
            claim.mentions[1].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            }),
            "the synthetic carrier is inserted at the add boundary"
        );
        assert_eq!(claim.mentions[2].opcode, b'D');
        assert_eq!(claim.mentions[3].opcode, b'U');
        assert!(
            claim.mentions[3].record_offset >= claim.mentions[2].record_end,
            "the later lifecycle's U/09 remains a separate packet-authored row"
        );
        assert_eq!(
            claim.mentions[3].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            }),
            "the later U/09 can still reconcile its own parser-owned appearance branch"
        );
    }

    #[test]
    fn exact_placeable_add_module_custom_add_only_synthesizes_following_update() {
        let object_id = 0x8000_34D8u32;
        let target_resref = *b"plc_custom_add\0\0";
        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            true,  // useable.
            false, // trap disarmable.
            true,  // lockable.
            false, // locked.
            false, // unknown 0x1AC sibling.
            true,  // name-valid.
            false, // EE-only light/visual guard before the transform map.
        ]);
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("add-only A/09 payload");
        let original_len = payload.len();
        let pre_claim =
            claim_payload_if_verified(&payload).expect("pre-rewrite exact fixed-width A/09");
        assert_eq!(pre_claim.mentions.len(), 1);
        assert_eq!(
            pre_claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0011,
                resref: None,
            }),
            "A/09 has only the fixed-width appearance WORD before synthesis"
        );

        let area_context = crate::translate::area::AreaPlaceableContext {
            area_resref: "testarea".to_string(),
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0xFFFE,
                module_template_resref: Some(target_resref),
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    useable: true,
                    trap_flag: false,
                    trap_disarmable: false,
                    lockable: true,
                    locked: false,
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("add-only custom A/09 should synthesize a parser-owned U/09 carrier");
        assert_eq!(summary.add_records_examined, 1);
        assert_eq!(summary.update_records_examined, 0);
        assert_eq!(summary.add_records_rewritten, 1);
        assert_eq!(summary.update_records_rewritten, 0);
        assert_eq!(summary.exact_placeable_appearance_custom_skipped, 1);
        assert_eq!(
            summary.exact_placeable_add_module_custom_appearance_skipped,
            1
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_skipped,
            1
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_with_update,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_update_only,
            0
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_add_only,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update,
            1
        );
        assert_synthesized_custom_carrier_origins(&summary, 1, 0);
        assert_synthesized_custom_carrier_after_add_reasons(&summary, 1, 0, 0, 0);
        assert_eq!(summary.exact_placeable_add_appearance_rewritten, 0);
        assert_eq!(summary.exact_placeable_update_appearance_rewritten, 0);
        assert_eq!(
            summary.bytes_inserted,
            (LEGACY_UPDATE_HEADER_BYTES
                + EE_UPDATE_APPEARANCE_WORD_READ_BYTES
                + EE_UPDATE_APPEARANCE_RESREF_READ_BYTES) as u32
        );
        assert_eq!(summary.bits_inserted, 0);
        assert_eq!(summary.bits_removed, 0);
        assert_eq!(
            summary.new_live_bytes_length,
            summary.old_live_bytes_length + 28
        );
        assert_eq!(payload.len(), original_len + 28);

        let claim = claim_payload_if_verified(&payload)
            .expect("post-rewrite exact A/09 plus synthesized U/09 claim");
        assert_eq!(claim.mentions.len(), 2);
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0011,
                resref: None,
            }),
            "the fixed-width add remains packet-authored"
        );
        assert_eq!(claim.mentions[1].record_offset, add_end);
        assert_eq!(
            claim.mentions[1].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            }),
            "the synthetic following U/09 owns EE's custom WORD + CResRef branch"
        );
        assert_eq!(
            claim.mentions[1].placeable_appearance_claim,
            Some(LiveObjectPlaceableAppearanceClaim {
                appearance_offset: add_end + LEGACY_UPDATE_HEADER_BYTES,
                resref_offset: Some(
                    add_end + LEGACY_UPDATE_HEADER_BYTES + EE_UPDATE_APPEARANCE_WORD_READ_BYTES
                ),
            })
        );
        assert_eq!(
            claim.mentions[1].fragment_bit_start, claim.mentions[0].fragment_bit_end,
            "the synthetic appearance-only update consumes no fragment bits"
        );
        assert_eq!(
            claim.mentions[1].fragment_bit_end, claim.mentions[0].fragment_bit_end,
            "the synthetic appearance-only update must not move the bit cursor"
        );
    }

    #[test]
    fn exact_placeable_add_reconciles_unique_area_static_state_with_optional_object_id() {
        let object_id = 0x8000_34D8u32;
        let optional_target = 0x8000_1234u32;
        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&optional_target.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            true,  // optional object id bytes are present before the visual map.
            false, // static/plot stays packet-authored.
            false, // useable conflicts with the unique module static row.
            true,  // trap-disarmable conflicts with the unique module static row.
            false, // lockable conflicts with the unique module static row.
            true,  // locked conflicts with the unique module static row.
            false, // unknown 0x1AC sibling stays packet-authored.
            true,  // name-valid stays packet-authored.
            false, // EE-only light/visual guard before the transform map.
        ]);
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("exact A/09 payload");
        claim_payload_if_verified(&payload).expect("pre-rewrite optional-object A/09 exact claim");

        let area_context = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0x0011,
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    useable: true,
                    trap_flag: false,
                    trap_disarmable: false,
                    lockable: true,
                    locked: false,
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("unique static context should reconcile optional-object A/09 state bits");
        assert_eq!(summary.add_records_examined, 1);
        assert_eq!(summary.update_records_examined, 0);
        assert_eq!(summary.add_records_rewritten, 1);
        assert_eq!(summary.bits_inserted, 0);
        assert_eq!(summary.bits_removed, 0);

        let claim = claim_payload_if_verified(&payload).expect("post-rewrite exact claim");
        assert_eq!(
            claim.mentions[0].placeable_state,
            Some(LiveObjectPlaceableState {
                useable: Some(true),
                trap_disarmable: Some(false),
                lockable: Some(true),
                locked: Some(false),
            })
        );
        let rewritten_bits =
            bits::decode_msb_valid_bits(&payload[claim.declared..], CNW_FRAGMENT_HEADER_BITS)
                .expect("rewritten exact A/09 fragment bits");
        assert!(
            rewritten_bits[CNW_FRAGMENT_HEADER_BITS + 2],
            "the optional-object guard bit must stay tied to the byte layout"
        );
        assert_eq!(
            &payload[claim.declared
                - visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES_LEN
                - 4
                ..claim.declared - visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES_LEN],
            &optional_target.to_le_bytes(),
            "optional object id bytes must remain packet-authored"
        );
    }

