fn live_object_source_window_item_update_claim(
    live_bytes: &[u8],
    row: &LiveObjectSourceWindowRow,
    fragment_bits: &[bool],
    bit_cursor: usize,
) -> Option<(&'static str, usize)> {
    let claim = item::parse_item_update_rewrite_claim(
        live_bytes,
        row.offset,
        row.record_end,
        fragment_bits,
        bit_cursor,
    )?;
    Some((
        if claim.mask_changed() {
            "item-update-translated"
        } else {
            "item-update"
        },
        claim.cursor.next_bit_cursor,
    ))
}

fn live_object_source_window_generic_update_claim(
    live_bytes: &[u8],
    row: &LiveObjectSourceWindowRow,
    fragment_bits: &[bool],
    bit_cursor: usize,
) -> Option<(&'static str, usize)> {
    let mut update_cursor = bit_cursor;
    if record::advance_verified_update_record_for_ee(
        live_bytes,
        row.offset,
        row.record_end,
        fragment_bits,
        &mut update_cursor,
    ) {
        Some(("update", update_cursor))
    } else {
        None
    }
}

fn live_object_source_window_item_neighbor_cursor_claims(
    live_bytes: &[u8],
    row: &LiveObjectSourceWindowRow,
    fragment_bits: &[bool],
    expected_bit_cursor: usize,
    preceding_claim_bit_end: Option<usize>,
    rewrite_bit_ledger: &LiveObjectRewriteBitLedger,
) -> Vec<LiveObjectSourceWindowItemNeighborCursorClaim> {
    if row.opcode != b'U' || row.marker != ITEM_OBJECT_TYPE {
        return Vec::new();
    }

    let start = expected_bit_cursor.saturating_sub(4);
    let end = expected_bit_cursor
        .saturating_add(4)
        .min(fragment_bits.len());
    let mut claims = Vec::new();
    for cursor in start..=end {
        if cursor == expected_bit_cursor {
            continue;
        }
        let Some(claim) = item::parse_item_update_rewrite_claim(
            live_bytes,
            row.offset,
            row.record_end,
            fragment_bits,
            cursor,
        ) else {
            continue;
        };
        let verdict = live_object_item_update_cursor_handoff_verdict(rewrite_bit_ledger, cursor);
        claims.push(LiveObjectSourceWindowItemNeighborCursorClaim {
            delta: cursor as isize - expected_bit_cursor as isize,
            bit_start: cursor,
            bit_end: claim.cursor.next_bit_cursor,
            read_end: claim.cursor.read_end,
            translated_mask: claim.translated_mask,
            orientation_vector: claim.cursor.orientation_vector,
            relation: live_object_source_window_neighbor_relation(
                cursor,
                expected_bit_cursor,
                preceding_claim_bit_end,
            ),
            gap_origin: live_object_item_update_focus_gap_origin(
                claim.translated_mask,
                claim.cursor.orientation_vector,
                expected_bit_cursor,
                cursor,
            ),
            source_owner: verdict.source_owner,
            claimable_handoff: verdict.claimable_handoff,
            handoff_blocker: verdict.handoff_blocker,
        });
    }
    claims
}

fn live_object_source_window_neighbor_relation(
    candidate_bit_start: usize,
    expected_bit_start: usize,
    preceding_claim_bit_end: Option<usize>,
) -> &'static str {
    if candidate_bit_start < expected_bit_start {
        return if preceding_claim_bit_end.is_some_and(|bit_end| bit_end > candidate_bit_start) {
            "overlaps-previous-claim"
        } else {
            "before-focus-without-owner"
        };
    }

    if preceding_claim_bit_end.is_some_and(|bit_end| bit_end >= candidate_bit_start) {
        "prior-claim-owned"
    } else {
        "inside-focus-row"
    }
}

fn live_object_item_update_focus_gap_origin(
    translated_mask: u32,
    orientation_vector: Option<bool>,
    focus_bit_cursor: usize,
    candidate_bit_start: usize,
) -> LiveObjectUpdateItemCursorGapOrigin {
    if candidate_bit_start <= focus_bit_cursor {
        return LiveObjectUpdateItemCursorGapOrigin::NotAfterFocusCursor;
    }

    let mut cursor = focus_bit_cursor;
    if (translated_mask & LEGACY_UPDATE_POSITION_MASK) != 0 {
        let position_end = cursor.saturating_add(LEGACY_UPDATE_POSITION_FRAGMENT_BITS);
        if candidate_bit_start <= position_end {
            return if candidate_bit_start == position_end {
                LiveObjectUpdateItemCursorGapOrigin::FocusPositionBits
            } else {
                LiveObjectUpdateItemCursorGapOrigin::PartialFocusPositionBits
            };
        }
        cursor = position_end;
    }

    if (translated_mask & LEGACY_UPDATE_ORIENTATION_MASK) != 0 {
        let orientation_selector_end = cursor.saturating_add(1);
        if candidate_bit_start <= orientation_selector_end {
            return if candidate_bit_start == orientation_selector_end {
                LiveObjectUpdateItemCursorGapOrigin::FocusOrientationSelector
            } else {
                LiveObjectUpdateItemCursorGapOrigin::PartialFocusOrientationSelector
            };
        }
        cursor = orientation_selector_end;
        match orientation_vector {
            Some(true) => {
                let orientation_end =
                    cursor.saturating_add(EE_UPDATE_ORIENTATION_VECTOR_FRAGMENT_BITS);
                if candidate_bit_start <= orientation_end {
                    return LiveObjectUpdateItemCursorGapOrigin::FocusOrientationVectorPrefixBits;
                }
                cursor = orientation_end;
            }
            Some(false) => {
                let orientation_end =
                    cursor.saturating_add(EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS);
                if candidate_bit_start <= orientation_end {
                    return LiveObjectUpdateItemCursorGapOrigin::FocusOrientationScalarPrefixBits;
                }
                cursor = orientation_end;
            }
            None => {}
        }
    }

    if (translated_mask & LEGACY_UPDATE_STATE_MASK) != 0 {
        let state_end = cursor.saturating_add(LEGACY_UPDATE_STATE_FRAGMENT_BITS);
        if candidate_bit_start <= state_end {
            return LiveObjectUpdateItemCursorGapOrigin::FocusStatePrefixBits;
        }
    }

    if (translated_mask & LEGACY_UPDATE_NAME_MASK) != 0 {
        return LiveObjectUpdateItemCursorGapOrigin::FocusNameOrLocstringPrefixBits;
    }

    LiveObjectUpdateItemCursorGapOrigin::InsideFocusRowUnclassified
}

fn nearest_unowned_item_update_neighbor_cursor(
    live_bytes: &[u8],
    offset: usize,
    record_end: usize,
    fragment_bits: &[bool],
    bit_cursor: usize,
    rewrite_bit_ledger: &LiveObjectRewriteBitLedger,
) -> Option<LiveObjectItemUpdateUnownedNeighbor> {
    if live_bytes.get(offset) != Some(&b'U')
        || live_bytes.get(offset + 1) != Some(&ITEM_OBJECT_TYPE)
    {
        return None;
    }

    let start = bit_cursor.saturating_sub(4);
    let end = bit_cursor.saturating_add(4).min(fragment_bits.len());
    let mut best: Option<LiveObjectItemUpdateUnownedNeighbor> = None;
    let focus_failure = item::translated_ee_item_update_cursor_failure(
        live_bytes,
        offset,
        record_end,
        fragment_bits,
        bit_cursor,
    );
    for candidate_cursor in start..=end {
        if candidate_cursor <= bit_cursor {
            continue;
        }
        let Some(claim) = item::parse_item_update_rewrite_claim(
            live_bytes,
            offset,
            record_end,
            fragment_bits,
            candidate_cursor,
        ) else {
            continue;
        };
        let Some(gap) = rewrite_bit_ledger.gap_before_cursor(candidate_cursor) else {
            continue;
        };
        let verdict =
            live_object_item_update_cursor_handoff_verdict(rewrite_bit_ledger, candidate_cursor);
        if !matches!(
            verdict.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::UnownedEmittedGap
                | LiveObjectUpdateItemCursorSourceOwner::UnownedSourceGap
                | LiveObjectUpdateItemCursorSourceOwner::UnownedEmittedAndSourceGap
        ) {
            continue;
        }
        let emitted_gap_values = rewrite_bit_ledger.emitted_gap_values(fragment_bits, &gap);
        let source_gap_values = rewrite_bit_ledger.source_gap_values(fragment_bits, &gap);

        let candidate = LiveObjectItemUpdateUnownedNeighbor {
            delta: candidate_cursor as isize - bit_cursor as isize,
            bit_start: candidate_cursor,
            bit_end: claim.cursor.next_bit_cursor,
            read_end: claim.cursor.read_end,
            translated_mask: claim.translated_mask,
            orientation_vector: claim.cursor.orientation_vector,
            emitted_gap_bits: gap.emitted_gap_bits,
            emitted_gap_bit_start: gap.emitted_gap_bit_start,
            emitted_gap_bit_end: gap.emitted_gap_bit_end,
            emitted_gap_values: live_object_rewrite_bit_slice_evidence(
                gap.emitted_gap_bit_start,
                gap.emitted_gap_bit_end,
                emitted_gap_values,
            ),
            source_gap_bits: gap.source_gap_bits,
            source_gap_bit_start: gap.source_gap_bit_start,
            source_gap_bit_end: gap.source_gap_bit_end,
            source_gap_values: live_object_rewrite_bit_slice_evidence(
                gap.source_gap_bit_start,
                gap.source_gap_bit_end,
                source_gap_values,
            ),
            previous_offset: gap.previous_offset,
            previous_record_end: gap.previous_record_end,
            previous_family: gap.previous_family,
            gap_origin: live_object_item_update_focus_gap_origin(
                claim.translated_mask,
                claim.cursor.orientation_vector,
                bit_cursor,
                candidate_cursor,
            ),
            source_owner: verdict.source_owner,
            claimable_handoff: verdict.claimable_handoff,
            handoff_blocker: verdict.handoff_blocker,
            focus_failure_stage: focus_failure
                .map(|failure| failure.stage.as_str())
                .unwrap_or("none"),
            focus_failure_mask: focus_failure.and_then(|failure| failure.mask),
            focus_failure_read_cursor: focus_failure
                .map(|failure| failure.read_cursor)
                .unwrap_or(offset),
            focus_failure_bit_cursor: focus_failure
                .map(|failure| failure.bit_cursor)
                .unwrap_or(bit_cursor),
            focus_failure_orientation_vector: focus_failure
                .and_then(|failure| failure.orientation_vector),
        };
        if best.is_none_or(|current| {
            candidate.bit_start.saturating_sub(bit_cursor)
                < current.bit_start.saturating_sub(bit_cursor)
        }) {
            best = Some(candidate);
        }
    }

    best
}

fn trace_item_update_source_window(
    reason: &'static str,
    live_bytes: &[u8],
    focus_offset: usize,
    focus_record_end: usize,
    fragment_bits: &[bool],
    bit_cursor: usize,
    rewrite_bit_ledger: &LiveObjectRewriteBitLedger,
) {
    if !debug_live_claim_enabled_for_span(focus_offset, focus_record_end) {
        return;
    }

    let before_start = bit_cursor.saturating_sub(16);
    let before_bits = fragment_bits.get(before_start..bit_cursor).unwrap_or(&[]);
    let after_bits = fragment_bits
        .get(bit_cursor..bit_cursor.saturating_add(32).min(fragment_bits.len()))
        .unwrap_or(&[]);
    eprintln!(
        "live-object item update source window: reason={reason} focus_offset={focus_offset} focus_record_end={focus_record_end} bit_cursor={bit_cursor} fragment_bits={} before_cursor_bits={before_bits:?} after_cursor_bits={after_bits:?}",
        fragment_bits.len()
    );
    for entry in rewrite_bit_ledger.recent_entries(8) {
        let source_values = format_bit_values_preview(
            rewrite_bit_ledger.source_values_for_entry(fragment_bits, entry),
        );
        let emitted_values = format_bit_values_preview(
            rewrite_bit_ledger.emitted_values_for_entry(fragment_bits, entry),
        );
        eprintln!(
            "live-object rewrite bit ledger row: offset={} record_end={} opcode=0x{:02X} marker=0x{:02X} family={} source_bits={}..{} source_delta={} source_values={} emitted_bits={}..{} emitted_delta={} emitted_values={} bits_inserted={} bits_removed={}",
            entry.offset,
            entry.record_end,
            entry.opcode,
            entry.marker,
            entry.family,
            entry.source_bit_start,
            entry.source_bit_end,
            entry.source_bit_end.saturating_sub(entry.source_bit_start),
            source_values,
            entry.emitted_bit_start,
            entry.emitted_bit_end,
            entry
                .emitted_bit_end
                .saturating_sub(entry.emitted_bit_start),
            emitted_values,
            entry.bits_inserted,
            entry.bits_removed
        );
    }
    if let Some(gap) = rewrite_bit_ledger.gap_before_cursor(bit_cursor) {
        let emitted_gap_bits = rewrite_bit_ledger.emitted_gap_values(fragment_bits, &gap);
        let source_gap_bits = rewrite_bit_ledger.source_gap_values(fragment_bits, &gap);
        eprintln!(
            "live-object rewrite bit ledger focus cursor: cursor={} relation={} emitted_gap_bits={} emitted_gap={}..{} emitted_gap_values={:?} source_relation={} source_gap_bits={} source_gap={}..{} source_gap_values={:?} implied_source_cursor={} cumulative_emitted_source_delta={} source_emitted_delta_after_previous={} previous_offset={} previous_record_end={} previous_family={} previous_source={}..{} previous_emitted={}..{} contiguous_tail={}",
            gap.cursor,
            gap.relation,
            gap.emitted_gap_bits,
            gap.emitted_gap_bit_start,
            gap.emitted_gap_bit_end,
            emitted_gap_bits,
            gap.source_relation,
            gap.source_gap_bits,
            gap.source_gap_bit_start,
            gap.source_gap_bit_end,
            source_gap_bits,
            gap.implied_source_cursor,
            gap.cumulative_emitted_source_delta,
            gap.source_emitted_delta_after_previous,
            gap.previous_offset,
            gap.previous_record_end,
            gap.previous_family,
            gap.previous_source_bit_start,
            gap.previous_source_bit_end,
            gap.previous_emitted_bit_start,
            gap.previous_emitted_bit_end,
            format_rewrite_bit_ledger_contiguous_tail(rewrite_bit_ledger, bit_cursor)
        );
    }

    let rows = live_object_source_window_rows(live_bytes, focus_offset, focus_record_end, 6, 3);
    let initial_bit_cursor =
        live_object_source_window_initial_bit_cursor(&rows, bit_cursor, rewrite_bit_ledger);
    let row_claims = live_object_source_window_row_bit_claims(
        live_bytes,
        &rows,
        fragment_bits,
        initial_bit_cursor,
    );
    for (row, claim) in rows.iter().zip(row_claims.iter()) {
        let preview = live_bytes
            .get(row.offset..row.record_end.min(row.offset.saturating_add(32)))
            .unwrap_or(&[]);
        let object_id = row
            .object_id
            .map(|value| format!("0x{value:08X}"))
            .unwrap_or_else(|| "none".to_string());
        let update_mask = row
            .update_mask
            .map(|value| format!("0x{value:08X}"))
            .unwrap_or_else(|| "none".to_string());
        let bit_end = claim
            .bit_end
            .map(|value| value.to_string())
            .unwrap_or_else(|| "none".to_string());
        let bit_delta = claim
            .bit_end
            .map(|value| value.saturating_sub(claim.bit_start).to_string())
            .unwrap_or_else(|| "none".to_string());
        eprintln!(
            "live-object item update source window row: offset={} record_end={} len={} opcode=0x{:02X} marker=0x{:02X} object_id={} update_mask={} bit_start={} bit_end={} bit_delta={} claim_family={} preview={:02X?}",
            row.offset,
            row.record_end,
            row.record_end.saturating_sub(row.offset),
            row.opcode,
            row.marker,
            object_id,
            update_mask,
            claim.bit_start,
            bit_end,
            bit_delta,
            claim.family,
            preview
        );
    }

    if let Some((focus_index, focus_row)) = rows
        .iter()
        .enumerate()
        .find(|(_, row)| row.offset == focus_offset)
    {
        let expected_bit_cursor = row_claims
            .get(focus_index)
            .map(|claim| claim.bit_start)
            .unwrap_or(bit_cursor);
        if let Some(failure) = item::translated_ee_item_update_cursor_failure(
            live_bytes,
            focus_row.offset,
            focus_row.record_end,
            fragment_bits,
            expected_bit_cursor,
        ) {
            if expected_bit_cursor != bit_cursor {
                if let Some(gap) = rewrite_bit_ledger.gap_before_cursor(expected_bit_cursor) {
                    let emitted_gap_bits =
                        rewrite_bit_ledger.emitted_gap_values(fragment_bits, &gap);
                    let source_gap_bits = rewrite_bit_ledger.source_gap_values(fragment_bits, &gap);
                    eprintln!(
                        "live-object rewrite bit ledger expected cursor: cursor={} relation={} emitted_gap_bits={} emitted_gap={}..{} emitted_gap_values={:?} source_relation={} source_gap_bits={} source_gap={}..{} source_gap_values={:?} implied_source_cursor={} cumulative_emitted_source_delta={} source_emitted_delta_after_previous={} previous_offset={} previous_record_end={} previous_family={} previous_source={}..{} previous_emitted={}..{} contiguous_tail={}",
                        gap.cursor,
                        gap.relation,
                        gap.emitted_gap_bits,
                        gap.emitted_gap_bit_start,
                        gap.emitted_gap_bit_end,
                        emitted_gap_bits,
                        gap.source_relation,
                        gap.source_gap_bits,
                        gap.source_gap_bit_start,
                        gap.source_gap_bit_end,
                        source_gap_bits,
                        gap.implied_source_cursor,
                        gap.cumulative_emitted_source_delta,
                        gap.source_emitted_delta_after_previous,
                        gap.previous_offset,
                        gap.previous_record_end,
                        gap.previous_family,
                        gap.previous_source_bit_start,
                        gap.previous_source_bit_end,
                        gap.previous_emitted_bit_start,
                        gap.previous_emitted_bit_end,
                        format_rewrite_bit_ledger_contiguous_tail(
                            rewrite_bit_ledger,
                            expected_bit_cursor,
                        )
                    );
                }
            }
            let failure_mask = failure
                .mask
                .map(|mask| format!("0x{mask:08X}"))
                .unwrap_or_else(|| "none".to_string());
            let orientation = failure
                .orientation_vector
                .map(|value| value.to_string())
                .unwrap_or_else(|| "none".to_string());
            eprintln!(
                "live-object item update source window focus failure: focus_offset={focus_offset} expected_bit_cursor={expected_bit_cursor} stage={} read_cursor={} fail_bit_cursor={} mask={} orientation_vector={}",
                failure.stage.as_str(),
                failure.read_cursor,
                failure.bit_cursor,
                failure_mask,
                orientation
            );
        }
        let preceding_claim_bit_end = focus_index
            .checked_sub(1)
            .and_then(|previous| row_claims.get(previous))
            .and_then(|claim| claim.bit_end);
        for neighbor in live_object_source_window_item_neighbor_cursor_claims(
            live_bytes,
            focus_row,
            fragment_bits,
            expected_bit_cursor,
            preceding_claim_bit_end,
            rewrite_bit_ledger,
        ) {
            let orientation = neighbor
                .orientation_vector
                .map(|value| value.to_string())
                .unwrap_or_else(|| "none".to_string());
            let ledger_gap = rewrite_bit_ledger.gap_before_cursor(neighbor.bit_start);
            let ledger_relation = ledger_gap.map(|gap| gap.relation).unwrap_or("no-ledger");
            let ledger_emitted_gap_bits = ledger_gap
                .map(|gap| gap.emitted_gap_bits.to_string())
                .unwrap_or_else(|| "none".to_string());
            let ledger_source_delta = ledger_gap
                .map(|gap| gap.source_emitted_delta_after_previous.to_string())
                .unwrap_or_else(|| "none".to_string());
            let ledger_cumulative_delta = ledger_gap
                .map(|gap| gap.cumulative_emitted_source_delta.to_string())
                .unwrap_or_else(|| "none".to_string());
            let ledger_source_relation = ledger_gap
                .map(|gap| gap.source_relation)
                .unwrap_or("no-ledger");
            let ledger_source_gap_bits = ledger_gap
                .map(|gap| gap.source_gap_bits.to_string())
                .unwrap_or_else(|| "none".to_string());
            let ledger_emitted_gap_range = ledger_gap
                .map(|gap| format!("{}..{}", gap.emitted_gap_bit_start, gap.emitted_gap_bit_end))
                .unwrap_or_else(|| "none".to_string());
            let ledger_source_gap_range = ledger_gap
                .map(|gap| format!("{}..{}", gap.source_gap_bit_start, gap.source_gap_bit_end))
                .unwrap_or_else(|| "none".to_string());
            let ledger_emitted_gap_values = ledger_gap
                .map(|gap| {
                    format!(
                        "{:?}",
                        rewrite_bit_ledger.emitted_gap_values(fragment_bits, &gap)
                    )
                })
                .unwrap_or_else(|| "none".to_string());
            let ledger_source_gap_values = ledger_gap
                .map(|gap| {
                    format!(
                        "{:?}",
                        rewrite_bit_ledger.source_gap_values(fragment_bits, &gap)
                    )
                })
                .unwrap_or_else(|| "none".to_string());
            let ledger_implied_source_cursor = ledger_gap
                .map(|gap| gap.implied_source_cursor.to_string())
                .unwrap_or_else(|| "none".to_string());
            let ledger_previous = ledger_gap
                .map(|gap| {
                    format!(
                        "{}..{}:{}",
                        gap.previous_offset, gap.previous_record_end, gap.previous_family
                    )
                })
                .unwrap_or_else(|| "none".to_string());
            let ledger_tail =
                format_rewrite_bit_ledger_contiguous_tail(rewrite_bit_ledger, neighbor.bit_start);
            eprintln!(
                "live-object item update source window neighboring cursor: focus_offset={focus_offset} expected_bit_cursor={expected_bit_cursor} delta={} bit_start={} bit_end={} read_end={} translated_mask=0x{:08X} orientation_vector={} relation={} gap_origin={} source_owner={} claimable_handoff={} handoff_blocker={} ledger_relation={} ledger_emitted_gap_bits={} ledger_emitted_gap={} ledger_emitted_gap_values={} ledger_source_relation={} ledger_source_gap_bits={} ledger_source_gap={} ledger_source_gap_values={} ledger_implied_source_cursor={} ledger_cumulative_emitted_source_delta={} ledger_source_emitted_delta_after_previous={} ledger_previous={} ledger_contiguous_tail={}",
                neighbor.delta,
                neighbor.bit_start,
                neighbor.bit_end,
                neighbor.read_end,
                neighbor.translated_mask,
                orientation,
                neighbor.relation,
                neighbor.gap_origin.as_str(),
                neighbor.source_owner.as_str(),
                neighbor.claimable_handoff,
                neighbor.handoff_blocker,
                ledger_relation,
                ledger_emitted_gap_bits,
                ledger_emitted_gap_range,
                ledger_emitted_gap_values,
                ledger_source_relation,
                ledger_source_gap_bits,
                ledger_source_gap_range,
                ledger_source_gap_values,
                ledger_implied_source_cursor,
                ledger_cumulative_delta,
                ledger_source_delta,
                ledger_previous,
                ledger_tail
            );
        }
    }
}

fn format_rewrite_bit_ledger_contiguous_tail(
    rewrite_bit_ledger: &LiveObjectRewriteBitLedger,
    cursor: usize,
) -> String {
    let Some(tail) = rewrite_bit_ledger.contiguous_tail_before_cursor(cursor) else {
        return "none".to_string();
    };
    format!(
        "entries={} families={} rows={} source={}..{} emitted={}..{} emitted_gap_to_cursor={} source_gap_to_cursor={}",
        tail.entry_count,
        rewrite_bit_ledger.contiguous_tail_family_chain(tail),
        rewrite_bit_ledger.contiguous_tail_row_chain(tail),
        tail.source_bit_start,
        tail.source_bit_end,
        tail.emitted_bit_start,
        tail.emitted_bit_end,
        tail.emitted_gap_to_cursor,
        tail.source_gap_to_cursor,
    )
}

fn trace_update_rewrite_record_candidate(
    live_bytes: &[u8],
    offset: usize,
    record_end: usize,
    bit_cursor: usize,
    bit_cursor_reliable: bool,
) {
    if !debug_live_claim_enabled_for_span(offset, record_end) {
        return;
    }
    let preview_end = record_end
        .min(live_bytes.len())
        .min(offset.saturating_add(32));
    let preview = live_bytes.get(offset..preview_end).unwrap_or(&[]);
    eprintln!(
        "live-object update rewrite record candidate: offset={offset} record_end={record_end} bit_cursor={bit_cursor} bit_cursor_reliable={bit_cursor_reliable} opcode=0x{:02X} marker=0x{:02X} preview={:02X?}",
        live_bytes.get(offset).copied().unwrap_or_default(),
        live_bytes.get(offset + 1).copied().unwrap_or_default(),
        preview
    );
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct UnclassifiedInterRecordSpanSummary {
    span_start: usize,
    span_end: usize,
    span_len: usize,
    next_opcode: u8,
    next_marker: u8,
    cnw_final_bits: Option<usize>,
    cnw_valid_bits: Option<usize>,
    cnw_payload_bits: Option<usize>,
    all_zero: bool,
}

fn summarize_unclassified_inter_record_span(
    live_bytes: &[u8],
    span_start: usize,
) -> Option<UnclassifiedInterRecordSpanSummary> {
    if span_start >= live_bytes.len()
        || boundary::looks_like_legacy_live_object_sub_message_boundary(live_bytes, span_start)
    {
        return None;
    }
    let span_end = ((span_start + 1)..live_bytes.len().saturating_sub(1)).find(|candidate| {
        boundary::looks_like_legacy_live_object_sub_message_boundary(live_bytes, *candidate)
    })?;
    let span = live_bytes.get(span_start..span_end)?;
    let cnw_final_bits = span.first().map(|byte| usize::from((byte & 0xE0) >> 5));
    let decoded = bits::decode_msb_valid_bits(span, CNW_FRAGMENT_HEADER_BITS);
    let cnw_valid_bits = decoded.as_ref().map(Vec::len);
    let cnw_payload_bits = cnw_valid_bits.and_then(|valid_bits| {
        valid_bits
            .checked_sub(CNW_FRAGMENT_HEADER_BITS)
            .filter(|payload_bits| *payload_bits > 0)
    });
    Some(UnclassifiedInterRecordSpanSummary {
        span_start,
        span_end,
        span_len: span.len(),
        next_opcode: live_bytes.get(span_end).copied().unwrap_or_default(),
        next_marker: live_bytes.get(span_end + 1).copied().unwrap_or_default(),
        cnw_final_bits,
        cnw_valid_bits,
        cnw_payload_bits,
        all_zero: span.iter().all(|byte| *byte == 0),
    })
}

fn trace_unclassified_inter_record_span(
    live_bytes: &[u8],
    span_start: usize,
    bit_cursor: usize,
    fragment_bits_len: usize,
    changed: bool,
) {
    let Some(summary) = summarize_unclassified_inter_record_span(live_bytes, span_start) else {
        return;
    };
    if !debug_live_claim_enabled_for_span(summary.span_start, summary.span_end) {
        return;
    }
    let preview = live_bytes
        .get(summary.span_start..summary.span_end.min(summary.span_start + 40))
        .unwrap_or(&[]);
    eprintln!(
        "live-object unclassified inter-record span: span_start={} span_end={} span_bytes={} next_opcode=0x{:02X} next_marker=0x{:02X} bit_cursor={bit_cursor} fragment_bits={fragment_bits_len} changed={changed} cnw_final_bits={:?} cnw_valid_bits={:?} cnw_payload_bits={:?} all_zero={} preview={:02X?}",
        summary.span_start,
        summary.span_end,
        summary.span_len,
        summary.next_opcode,
        summary.next_marker,
        summary.cnw_final_bits,
        summary.cnw_valid_bits,
        summary.cnw_payload_bits,
        summary.all_zero,
        preview
    );
}

fn debug_live_claim_enabled_for_span(span_start: usize, span_end: usize) -> bool {
    if std::env::var_os("HGBRIDGE_PROXY2_DEBUG_LIVE_CLAIM").is_none() {
        return false;
    }
    let Ok(filter) = std::env::var("HGBRIDGE_PROXY2_DEBUG_LIVE_CLAIM_OWNER_OFFSET") else {
        return true;
    };
    filter.split(',').any(|part| {
        part.trim()
            .parse::<usize>()
            .map(|wanted| wanted == span_start || wanted == span_end)
            .unwrap_or(false)
    })
}

fn read_u32_le(bytes: &[u8], offset: usize) -> Option<u32> {
    let bytes = bytes.get(offset..offset + 4)?;
    Some(u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]))
}

fn read_u16_le(bytes: &[u8], offset: usize) -> Option<u16> {
    let bytes = bytes.get(offset..offset + 2)?;
    Some(u16::from_le_bytes([bytes[0], bytes[1]]))
}

fn read_f32_le(bytes: &[u8], offset: usize) -> Option<f32> {
    let bytes = bytes.get(offset..offset + 4)?;
    Some(f32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]))
}

fn write_u32_le(bytes: &mut [u8], offset: usize, value: u32) -> Option<()> {
    bytes
        .get_mut(offset..offset + 4)?
        .copy_from_slice(&value.to_le_bytes());
    Some(())
}

fn write_u16_le(bytes: &mut [u8], offset: usize, value: u16) -> Option<()> {
    bytes
        .get_mut(offset..offset + 2)?
        .copy_from_slice(&value.to_le_bytes());
    Some(())
}

/// Dump a live-object payload that was accepted or rejected by a semantic
/// ownership probe.
///
/// This is intentionally environment-gated and lives beside the live-object
/// translator rather than as ad-hoc test output.  The strict bridge treats a
/// no-op live-object claim as provisional evidence: captured payloads should be
/// promoted into fixtures and then either assigned to an exact translator or
/// rejected. These probe dumps are written below the diagnostics subdirectory
/// instead of the quarantine root so rejected split candidates do not look like
/// packets the proxy actually refused to emit. Set `NWN_BRIDGE_QUARANTINE_DIR`
/// to enable capture. The older `HGBRIDGE_PROXY2_DUMP_MODULE_INFO_DIR` name is
/// still accepted as a fallback.
pub fn dump_live_object_fixture_candidate(payload: &[u8], reason: &str) {
    let Some(dir) = crate::translate::diagnostics::probe_dump_dir() else {
        return;
    };

    let sanitized_reason = sanitize_live_object_dump_reason(reason);
    let key = LiveObjectFixtureDumpKey {
        reason: sanitized_reason.clone(),
        signature: live_object_fixture_dump_signature(payload, &sanitized_reason),
    };
    let keys = LIVE_OBJECT_FIXTURE_DUMP_KEYS.get_or_init(|| Mutex::new(HashSet::new()));
    match keys.lock() {
        Ok(mut keys) => {
            if !keys.insert(key) {
                tracing::debug!(
                    reason = sanitized_reason,
                    payload_length = payload.len(),
                    "duplicate live-object fixture candidate dump suppressed"
                );
                return;
            }
        }
        Err(error) => {
            tracing::warn!(
                %error,
                reason = sanitized_reason,
                payload_length = payload.len(),
                "live-object fixture candidate dump dedupe state poisoned; skipping diagnostic dump"
            );
            return;
        }
    }

    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or(0);
    let mut path = dir;
    if std::fs::create_dir_all(&path).is_err() {
        return;
    }
    path.push(format!(
        "{}-len{}-{}.bin",
        sanitized_reason,
        payload.len(),
        nanos
    ));
    let _ = std::fs::write(path, payload);
}

pub fn dump_live_object_update_rewrite_failure_evidence(
    payload: &[u8],
    source: &str,
    failure: LiveObjectUpdateRewriteFailure,
) {
    if payload.len() > MAX_REASONABLE_LIVE_PAYLOAD_BYTES {
        return;
    }
    let Some(mut dir) = crate::translate::diagnostics::probe_dump_dir() else {
        return;
    };

    let dump_reason = format!(
        "{}-{}-offset{}-bit{}",
        source, failure.reason, failure.offset, failure.bit_cursor
    );
    let sanitized_reason = sanitize_live_object_dump_reason(&dump_reason);
    let key = LiveObjectFixtureDumpKey {
        reason: sanitized_reason.clone(),
        signature: live_object_fixture_dump_signature(payload, &sanitized_reason),
    };
    let keys = LIVE_OBJECT_FAILURE_EVIDENCE_DUMP_KEYS.get_or_init(|| Mutex::new(HashSet::new()));
    match keys.lock() {
        Ok(mut keys) => {
            if !keys.insert(key) {
                tracing::debug!(
                    reason = sanitized_reason,
                    payload_length = payload.len(),
                    "duplicate live-object rewrite failure evidence dump suppressed"
                );
                return;
            }
        }
        Err(error) => {
            tracing::warn!(
                %error,
                reason = sanitized_reason,
                payload_length = payload.len(),
                "live-object rewrite failure evidence dedupe state poisoned; skipping diagnostic dump"
            );
            return;
        }
    }

    if std::fs::create_dir_all(&dir).is_err() {
        return;
    }
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or(0);
    let base_name = format!("{}-len{}-{}", sanitized_reason, payload.len(), nanos);

    dir.push(format!("{base_name}.bin"));
    let _ = std::fs::write(&dir, payload);
    dir.set_file_name(format!("{base_name}.txt"));
    let report = format_live_object_update_rewrite_failure_evidence(source, payload, failure);
    let _ = std::fs::write(dir, report);
}

fn format_live_object_update_rewrite_failure_evidence(
    source: &str,
    payload: &[u8],
    failure: LiveObjectUpdateRewriteFailure,
) -> String {
    use std::fmt::Write as _;

    let mut out = String::new();
    let gap_origin = failure
        .item_update_neighbor_gap_origin
        .map(|origin| origin.as_str())
        .unwrap_or("none");
    let _ = writeln!(&mut out, "source={source}");
    let _ = writeln!(&mut out, "payload_len={}", payload.len());
    let _ = writeln!(
        &mut out,
        "payload_prefix={}",
        crate::packet::hex_prefix(payload, 256)
    );
    let _ = writeln!(&mut out, "reason={}", failure.reason);
    let _ = writeln!(&mut out, "kind={}", failure.kind.as_str());
    let _ = writeln!(&mut out, "offset={}", failure.offset);
    let _ = writeln!(&mut out, "record_end={}", failure.record_end);
    let _ = writeln!(&mut out, "bit_cursor={}", failure.bit_cursor);
    let _ = writeln!(&mut out, "gap_origin={gap_origin}");

    if let Some(evidence) = failure.item_update_cursor_evidence {
        let _ = writeln!(
            &mut out,
            "focus_failure_stage={}",
            evidence.focus_failure_stage
        );
        let _ = writeln!(
            &mut out,
            "focus_failure_mask={}",
            format_optional_u32_hex(evidence.focus_failure_mask)
        );
        let _ = writeln!(
            &mut out,
            "focus_failure_read_cursor={}",
            evidence.focus_failure_read_cursor
        );
        let _ = writeln!(
            &mut out,
            "focus_failure_bit_cursor={}",
            evidence.focus_failure_bit_cursor
        );
        let _ = writeln!(
            &mut out,
            "focus_failure_orientation_vector={:?}",
            evidence.focus_failure_orientation_vector
        );
        write_item_cursor_ledger_evidence(
            &mut out,
            "focus_cursor_ledger",
            evidence.focus_cursor_ledger,
        );
        if let Some(read_window) = evidence.focus_failure_read_window {
            let _ = writeln!(
                &mut out,
                "focus_failure_read_window={}",
                format_rewrite_byte_slice_evidence(read_window)
            );
        } else {
            let _ = writeln!(&mut out, "focus_failure_read_window=none");
        }
        if let Some(bit_window) = evidence.focus_failure_bit_window {
            let _ = writeln!(
                &mut out,
                "focus_failure_bit_window={}",
                format_rewrite_bit_slice_evidence(bit_window)
            );
        } else {
            let _ = writeln!(&mut out, "focus_failure_bit_window=none");
        }
        let _ = writeln!(
            &mut out,
            "unowned_neighbor={:#?}",
            evidence.unowned_neighbor
        );
        if let Some(handoff) = evidence.item_handoff {
            let focus_update_mask = handoff
                .focus_update_mask
                .map(|mask| format!("0x{mask:08X}"))
                .unwrap_or_else(|| "none".to_string());
            let neighbor_orientation = handoff
                .neighbor_orientation_vector
                .map(|value| value.to_string())
                .unwrap_or_else(|| "none".to_string());
            let _ = writeln!(
                &mut out,
                "item_handoff_previous={}..{}:{}",
                handoff.previous_offset, handoff.previous_record_end, handoff.previous_family
            );
            let _ = writeln!(
                &mut out,
                "item_handoff_focus={}..{} bit_cursor={} update_mask={}",
                handoff.focus_offset,
                handoff.focus_record_end,
                handoff.focus_bit_cursor,
                focus_update_mask
            );
            let _ = writeln!(
                &mut out,
                "item_handoff_valid_neighbor=delta={} bits={}..{} read_end={} translated_mask=0x{:08X} orientation_vector={} gap_origin={}",
                handoff.neighbor_delta,
                handoff.neighbor_bit_start,
                handoff.neighbor_bit_end,
                handoff.neighbor_read_end,
                handoff.neighbor_translated_mask,
                neighbor_orientation,
                handoff.gap_origin.as_str()
            );
            let _ = writeln!(
                &mut out,
                "item_handoff_source_owner={} claimable_handoff={} handoff_blocker={}",
                handoff.source_owner.as_str(),
                handoff.claimable_handoff,
                handoff.handoff_blocker
            );
            let _ = writeln!(
                &mut out,
                "item_handoff_emitted_gap=bits={} range={}..{} values={}",
                handoff.emitted_gap_bits,
                handoff.emitted_gap_bit_start,
                handoff.emitted_gap_bit_end,
                format_rewrite_bit_slice_evidence(handoff.emitted_gap_values)
            );
            let _ = writeln!(
                &mut out,
                "item_handoff_source_gap=bits={} range={}..{} values={}",
                handoff.source_gap_bits,
                handoff.source_gap_bit_start,
                handoff.source_gap_bit_end,
                format_rewrite_bit_slice_evidence(handoff.source_gap_values)
            );
            if let Some(focus_bits) = handoff.focus_source_bits {
                let _ = writeln!(
                    &mut out,
                    "item_handoff_focus_source_bits={}",
                    format_rewrite_bit_slice_evidence(focus_bits)
                );
            } else {
                let _ = writeln!(&mut out, "item_handoff_focus_source_bits=none");
            }
        } else {
            let _ = writeln!(&mut out, "item_handoff=none");
        }
        write_rewrite_tail_evidence(&mut out, evidence.contiguous_tail);
        write_source_window_evidence(&mut out, payload, evidence.source_window);
    } else {
        let _ = writeln!(&mut out, "item_update_cursor_evidence=none");
    }

    out
}

fn write_rewrite_tail_evidence(
    out: &mut String,
    tail: Option<LiveObjectUpdateRewriteTailEvidence>,
) {
    use std::fmt::Write as _;

    let Some(tail) = tail else {
        let _ = writeln!(out, "contiguous_tail=none");
        return;
    };

    let _ = writeln!(
        out,
        "contiguous_tail_summary=entries={} retained={} source={}..{} emitted={}..{} cursor={} source_cursor={} emitted_source_delta={} emitted_gap={} source_gap={}",
        tail.entry_count,
        tail.entries_retained,
        tail.source_bit_start,
        tail.source_bit_end,
        tail.emitted_bit_start,
        tail.emitted_bit_end,
        tail.emitted_cursor,
        tail.source_cursor,
        tail.emitted_source_delta,
        tail.emitted_gap_to_cursor,
        tail.source_gap_to_cursor
    );

    for (index, entry) in tail.entries.iter().flatten().enumerate() {
        let _ = writeln!(
            out,
            "contiguous_tail_entry[{index}]={}..{} opcode={} marker={} family={} source={}..{} source_bits={} emitted={}..{} emitted_bits={} inserted={} removed={}",
            entry.offset,
            entry.record_end,
            format_live_object_byte(entry.opcode),
            format_live_object_byte(entry.marker),
            entry.family,
            entry.source_bit_start,
            entry.source_bit_end,
            format_rewrite_bit_slice_evidence(entry.source_bits),
            entry.emitted_bit_start,
            entry.emitted_bit_end,
            format_rewrite_bit_slice_evidence(entry.emitted_bits),
            entry.bits_inserted,
            entry.bits_removed
        );
    }
}

fn write_source_window_evidence(
    out: &mut String,
    payload: &[u8],
    source_window: Option<LiveObjectUpdateSourceWindowEvidence>,
) {
    use std::fmt::Write as _;

    let Some(source_window) = source_window else {
        let _ = writeln!(out, "source_window=none");
        return;
    };

    let _ = writeln!(
        out,
        "source_window_summary=focus={}..{} focus_row_index={} initial_bit_cursor={} expected_bit_cursor={} fragment_bits={} entries={} retained={} neighbors={} retained={}",
        source_window.focus_offset,
        source_window.focus_record_end,
        format_optional_usize(source_window.focus_row_index),
        source_window.initial_bit_cursor,
        source_window.expected_bit_cursor,
        source_window.fragment_bit_count,
        source_window.entry_count,
        source_window.entries_retained,
        source_window.neighbor_count,
        source_window.neighbors_retained
    );

    for (index, entry) in source_window.entries.iter().flatten().enumerate() {
        let bits = entry
            .bit_end
            .map(|bit_end| format!("{}..{bit_end}", entry.bit_start))
            .unwrap_or_else(|| format!("{}..unclaimed", entry.bit_start));
        let _ = writeln!(
            out,
            "source_window_entry[{index}]={}..{} opcode={} marker={} object_id={} update_mask={} bits={} bit_delta={} claim={} source_bits={} bytes={}",
            entry.offset,
            entry.record_end,
            format_live_object_byte(entry.opcode),
            format_live_object_byte(entry.marker),
            format_optional_u32_hex(entry.object_id),
            format_optional_u32_hex(entry.update_mask),
            bits,
            format_optional_usize(entry.bit_delta),
            entry.claim_family,
            format_rewrite_bit_slice_evidence(entry.source_bits),
            format_payload_byte_range(payload, entry.offset, entry.record_end, 48)
        );
    }

    for (index, neighbor) in source_window.neighbors.iter().flatten().enumerate() {
        let _ = writeln!(
            out,
            "source_window_neighbor[{index}]=delta={} bits={}..{} read_end={} translated_mask=0x{:08X} orientation_vector={} relation={} gap_origin={} source_owner={} claimable_handoff={} handoff_blocker={} ledger_relation={} ledger_source_relation={} ledger_emitted_gap={} ledger_source_gap={} ledger_implied_source_cursor={} ledger_cumulative_emitted_source_delta={} ledger_source_emitted_delta_after_previous={} ledger_previous={}",
            neighbor.delta,
            neighbor.bit_start,
            neighbor.bit_end,
            neighbor.read_end,
            neighbor.translated_mask,
            format_optional_bool(neighbor.orientation_vector),
            neighbor.relation,
            neighbor.gap_origin.as_str(),
            neighbor.source_owner.as_str(),
            neighbor.claimable_handoff,
            neighbor.handoff_blocker,
            neighbor.ledger_relation,
            neighbor.ledger_source_relation,
            format_optional_gap(
                neighbor.ledger_emitted_gap_bits,
                neighbor.ledger_emitted_gap_bit_start,
                neighbor.ledger_emitted_gap_bit_end,
                neighbor.ledger_emitted_gap_values,
            ),
            format_optional_gap(
                neighbor.ledger_source_gap_bits,
                neighbor.ledger_source_gap_bit_start,
                neighbor.ledger_source_gap_bit_end,
                neighbor.ledger_source_gap_values,
            ),
            format_optional_usize(neighbor.ledger_implied_source_cursor),
            format_optional_isize(neighbor.ledger_cumulative_emitted_source_delta),
            format_optional_isize(neighbor.ledger_source_emitted_delta_after_previous),
            format_optional_previous_row(
                neighbor.ledger_previous_offset,
                neighbor.ledger_previous_record_end,
                neighbor.ledger_previous_family,
            )
        );
    }
}

fn write_item_cursor_ledger_evidence(
    out: &mut String,
    label: &str,
    ledger: Option<LiveObjectUpdateItemCursorLedgerEvidence>,
) {
    use std::fmt::Write as _;

    let Some(ledger) = ledger else {
        let _ = writeln!(out, "{label}=none");
        return;
    };

    let _ = writeln!(
        out,
        "{label}=source_owner={} claimable_handoff={} handoff_blocker={} ledger_relation={} ledger_source_relation={} ledger_emitted_gap={} ledger_source_gap={} ledger_implied_source_cursor={} ledger_cumulative_emitted_source_delta={} ledger_source_emitted_delta_after_previous={} ledger_previous={}",
        ledger.source_owner.as_str(),
        ledger.claimable_handoff,
        ledger.handoff_blocker,
        ledger.ledger_relation,
        ledger.ledger_source_relation,
        format_optional_gap(
            ledger.ledger_emitted_gap_bits,
            ledger.ledger_emitted_gap_bit_start,
            ledger.ledger_emitted_gap_bit_end,
            ledger.ledger_emitted_gap_values,
        ),
        format_optional_gap(
            ledger.ledger_source_gap_bits,
            ledger.ledger_source_gap_bit_start,
            ledger.ledger_source_gap_bit_end,
            ledger.ledger_source_gap_values,
        ),
        format_optional_usize(ledger.ledger_implied_source_cursor),
        format_optional_isize(ledger.ledger_cumulative_emitted_source_delta),
        format_optional_isize(ledger.ledger_source_emitted_delta_after_previous),
        format_optional_previous_row(
            ledger.ledger_previous_offset,
            ledger.ledger_previous_record_end,
            ledger.ledger_previous_family,
        )
    );
}

fn format_live_object_byte(value: u8) -> String {
    format!("0x{value:02X}")
}

fn format_optional_bool(value: Option<bool>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_usize(value: Option<usize>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_isize(value: Option<isize>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_u32_hex(value: Option<u32>) -> String {
    value
        .map(|value| format!("0x{value:08X}"))
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_gap(
    bits: Option<usize>,
    bit_start: Option<usize>,
    bit_end: Option<usize>,
    values: Option<LiveObjectUpdateRewriteBitSliceEvidence>,
) -> String {
    match (bits, bit_start, bit_end, values) {
        (Some(bits), Some(bit_start), Some(bit_end), Some(values)) => format!(
            "bits={bits} range={bit_start}..{bit_end} values={}",
            format_rewrite_bit_slice_evidence(values)
        ),
        (Some(bits), Some(bit_start), Some(bit_end), None) => {
            format!("bits={bits} range={bit_start}..{bit_end} values=none")
        }
        _ => "none".to_string(),
    }
}

fn format_optional_previous_row(
    offset: Option<usize>,
    record_end: Option<usize>,
    family: Option<&'static str>,
) -> String {
    match (offset, record_end, family) {
        (Some(offset), Some(record_end), Some(family)) => {
            format!("{offset}..{record_end}:{family}")
        }
        _ => "none".to_string(),
    }
}

fn format_payload_byte_range(payload: &[u8], start: usize, end: usize, limit: usize) -> String {
    use std::fmt::Write as _;

    let start = start.min(payload.len());
    let end = end.min(payload.len()).max(start);
    let bytes = &payload[start..end];
    let retained = bytes.len().min(limit);
    let mut hex = String::new();
    for (index, byte) in bytes.iter().take(retained).enumerate() {
        if index != 0 {
            hex.push(' ');
        }
        let _ = write!(&mut hex, "{byte:02X}");
    }
    if bytes.len() > retained {
        let omitted = bytes.len().saturating_sub(retained);
        if !hex.is_empty() {
            hex.push(' ');
        }
        let _ = write!(&mut hex, "...+{omitted}");
    }
    format!("{start}..{end}:{hex}")
}

fn format_rewrite_bit_slice_evidence(evidence: LiveObjectUpdateRewriteBitSliceEvidence) -> String {
    let mut bits = String::new();
    for value in evidence.bits.iter().take(evidence.bits_retained) {
        bits.push(match value {
            Some(true) => '1',
            Some(false) => '0',
            None => '?',
        });
    }
    if evidence.bits_retained < evidence.bit_count {
        format!(
            "{}..{}:{}...+{}",
            evidence.bit_start,
            evidence.bit_end,
            bits,
            evidence.bit_count.saturating_sub(evidence.bits_retained)
        )
    } else {
        format!("{}..{}:{}", evidence.bit_start, evidence.bit_end, bits)
    }
}

fn format_rewrite_byte_slice_evidence(
    evidence: LiveObjectUpdateRewriteByteSliceEvidence,
) -> String {
    use std::fmt::Write as _;

    let mut hex = String::new();
    for (index, value) in evidence
        .bytes
        .iter()
        .take(evidence.bytes_retained)
        .enumerate()
    {
        if index != 0 {
            hex.push(' ');
        }
        match value {
            Some(byte) => {
                let _ = write!(&mut hex, "{byte:02X}");
            }
            None => hex.push_str("??"),
        }
    }
    if evidence.bytes_retained < evidence.byte_count {
        let omitted = evidence.byte_count.saturating_sub(evidence.bytes_retained);
        if !hex.is_empty() {
            hex.push(' ');
        }
        let _ = write!(&mut hex, "...+{omitted}");
    }
    format!("{}..{}:{}", evidence.byte_start, evidence.byte_end, hex)
}

/// Return true when a live-object payload contains door/placeable add or update
/// records that require a family-specific semantic translator.
///
/// Decompile evidence: EE routes these through dedicated readers
/// (`sub_140796DD0` / `sub_140797780` for doors and `sub_1407A7800` /
/// `sub_1407A8460` for placeables). Even when a payload is otherwise
/// structurally walkable, the generic no-op claimed-record path must not own
/// these records because Diamond/HG streams can omit or compact EE-only visual,
/// orientation, and name-mode fields.
pub fn payload_contains_door_or_placeable_add_update_record(payload: &[u8]) -> bool {
    if payload.len() < HIGH_LEVEL_HEADER_BYTES + CNW_LENGTH_BYTES
        || payload[0] != HIGH_LEVEL_ENVELOPE
        || payload[1] != GAME_OBJECT_UPDATE_MAJOR
        || payload[2] != LIVE_OBJECT_MINOR
    {
        return false;
    }

    let Some(declared) =
        read_u32_le(payload, HIGH_LEVEL_HEADER_BYTES).and_then(|value| usize::try_from(value).ok())
    else {
        return false;
    };
    if declared < HIGH_LEVEL_HEADER_BYTES + CNW_LENGTH_BYTES || declared > payload.len() {
        return false;
    }

    let live_bytes = &payload[HIGH_LEVEL_HEADER_BYTES + CNW_LENGTH_BYTES..declared];
    let mut offset = 0usize;
    while offset + 2 <= live_bytes.len() {
        if !boundary::looks_like_legacy_live_object_sub_message_boundary(live_bytes, offset) {
            offset += 1;
            continue;
        }

        let opcode = live_bytes[offset];
        let object_type = live_bytes[offset + 1];
        if matches!(opcode, b'A' | b'U')
            && matches!(object_type, DOOR_OBJECT_TYPE | PLACEABLE_OBJECT_TYPE)
        {
            return true;
        }

        let next = boundary::find_next_legacy_live_object_sub_message_boundary_after(
            live_bytes,
            offset,
            live_bytes.len(),
        );
        offset = next.max(offset + 1);
    }

    false
}

#[cfg(all(test, hgbridge_private_fixtures))]
mod claimed_records_guard_tests {
    use super::*;

    #[test]
    fn door_mixed_add_update_payload_must_not_use_generic_claimed_records() {
        let payload = include_bytes!(
            "../../fixtures/live_object/hg_door_mixed_add_update_claimed_records.bin"
        );
        assert!(payload_contains_door_or_placeable_add_update_record(
            payload
        ));
    }

    #[test]
    fn placeable_mixed_add_update_payload_must_not_use_generic_claimed_records() {
        let payload = include_bytes!(
            "../../fixtures/live_object/hg_placeable_mixed_add_update_claimed_records.bin"
        );
        assert!(payload_contains_door_or_placeable_add_update_record(
            payload
        ));
    }
}
